1	// claim-office.ts
2	
3	export type Item = { type: string };
4	
5	export type QuoteInput = {
6	  items: Item[];
7	  customerYears: number;
8	  previousContracts: number;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const SWORD_BASE_PREMIUM = 100;
13	const AMULET_BASE_PREMIUM = 60;
14	const STAFF_BASE_PREMIUM = 80;
15	
16	function basePremiumFor(item: Item): number {
17	  if (item.type === "amulet") return AMULET_BASE_PREMIUM;
18	  if (item.type === "staff") return STAFF_BASE_PREMIUM;
19	  return SWORD_BASE_PREMIUM;
20	}
21	
22	export function quote(input: QuoteInput): number {
23	  const itemsBasePremium = input.items.reduce(
24	    (sum, item) => sum + basePremiumFor(item),
25	    0,
26	  );
27	  return itemsBasePremium + PROCESSING_FEE;
28	}
