103	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
104	  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
105	  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
106	  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
